  created() {
    this.current_index = this.$store.state.sort_answer_progress;
    this.update_current_question_info();
  },
  methods: {
    getShuffledArr(arr) {
      if (arr.length === 1) {
        return arr;
      }
      const rand = Math.floor(Math.random() * arr.length);
      return [
        arr[rand],
        ...this.getShuffledArr(arr.filter((_, i) => i != rand)),
      ];
    },
    update_current_question_info() {
      this.current_question_info.question = this.question_list[
        this.current_index
      ].question;
      this.current_question_info.answer = this.question_list[
        this.current_index
      ].answer;
      this.current_question_info.words = this.question_list[
        this.current_index
      ].words;
      this.current_question_info.random_words = this.getShuffledArr(
        this.question_list[this.current_index].words
      );
      this.current_question_info.sentence = "";
    },
    next() {
      console.log("next");
      this.current_index = this.current_index + 1;
      if (this.current_index > this.question_list.length - 1) {
        this.current_index = 0;
      }
      this.update_current_question_info();
      this.$store.commit("set_sort_answer_progress", this.current_index);
    },
    on_word_click(index, user_word) {
      if (user_word == this.current_question_info.words[0]) {
        //console.log(user_word)

        this.current_question_info.words.shift();
        //delete this.current_question_info.random_words[index]
        this.current_question_info.random_words.splice(index, 1);

        if (
          user_word ==
          this.current_question_info.answer.substring(0, user_word.length)
        ) {
          this.current_question_info.sentence += user_word;
          this.current_question_info.answer = this.current_question_info.answer.substring(
            user_word.length,
            this.current_question_info.answer.length
          );
        } else {
          let i = 0;
          for (; i < this.current_question_info.answer.length; i++) {
            let char = this.current_question_info.answer[i];
            if (char == user_word[0]) {
              let answer_copy = this.current_question_info.answer;
              let substring = answer_copy.substring(i, answer_copy.length);
              if (substring.substring(0, user_word.length) == user_word) {
                let target = this.current_question_info.answer.substring(0, i);
                this.current_question_info.answer = this.current_question_info.answer.substring(
                  i + user_word.length,
                  this.current_question_info.answer.length
                );
                this.current_question_info.sentence += target + user_word;
                break;
              }
            }
          }
        }

        if (this.current_question_info.words.length == 0) {
          this.next();
        }

        this.wrong_counting = 0;
        this.red_word = "";
        this.$forceUpdate();
      } else {
        this.wrong_counting += 1;
      }

      if (this.wrong_counting > 0) {
        this.red_word = this.current_question_info.words[0];
      }
      //console.log(user_word)
    },
  },
};
</script>

